import { inject, Injectable, signal, effect } from '@angular/core';
import { LocalStorageService } from '../../shared/services/local-storage.service';
import { AuthUserResponse } from '../../api';
import {
  LOCAL_STORAGE_KEY_SELECTED_SESSION_ID,
  LOCAL_STORAGE_KEY_USER_SESSION,
} from '../models';
import { isDefined } from '../../shared/utils';

@Injectable({
  providedIn: 'root',
})
export class UserSessionService {
  private readonly localStorageService = inject(LocalStorageService);

  // Private writable signals
  private readonly _userSessions = signal<AuthUserResponse[]>([]);
  private readonly _currentUserSession = signal<AuthUserResponse | null>(null);

  // Public readonly signals
  readonly userSessions = this._userSessions.asReadonly();
  readonly currentUserSession = this._currentUserSession.asReadonly();

  constructor() {
    this.loadSessionsFromStorage();

    effect(() => {
      const session = this._currentUserSession();
      if (session) {
        // Store with API-scoped namespace
        this.localStorageService.setItem(
          LOCAL_STORAGE_KEY_SELECTED_SESSION_ID,
          session.id,
          undefined,
          true,
        );
      } else {
        // Remove selected session ID when no current session is set
        this.localStorageService.removeItem(
          LOCAL_STORAGE_KEY_SELECTED_SESSION_ID,
          true,
        );
      }
    });
  }

  setUserSessions(sessions: AuthUserResponse[]): void {
    this._userSessions.set(sessions);
    // Store with API-scoped namespace, defensively handle serialization
    try {
      const serialized = JSON.stringify(sessions);
      this.localStorageService.setItem(
        LOCAL_STORAGE_KEY_USER_SESSION,
        serialized,
        undefined,
        true,
      );
    } catch {
      console.warn('[UserSessionService] Failed to serialize sessions');
    }
  }

  setCurrentUserSession(sessionId: string): void {
    const session = this._userSessions().find((s) => s.id === sessionId);
    if (isDefined(session)) {
      this._currentUserSession.set(session);
    }
  }

  private loadSessionsFromStorage(): void {
    const sessionsStr = this.localStorageService.getItem<string>(
      LOCAL_STORAGE_KEY_USER_SESSION,
      true,
    );
    if (isDefined(sessionsStr)) {
      try {
        const sessions = JSON.parse(sessionsStr) as AuthUserResponse[];
        this._userSessions.set(sessions);

        const selectedId = this.localStorageService.getItem<string>(
          LOCAL_STORAGE_KEY_SELECTED_SESSION_ID,
          true,
        );
        if (isDefined(selectedId)) {
          this.setCurrentUserSession(selectedId);
        }
      } catch {
        // Fail silently but safely if storage is corrupted
        this.clearAllSessions();
      }
    }
  }

  /**
   * Reloads sessions from storage.
   * Should be called after user profile is loaded to ensure correct namespace.
   */
  reloadSessionsFromStorage(): void {
    this.loadSessionsFromStorage();
  }

  clearAllSessions(): void {
    this._userSessions.set([]);
    this._currentUserSession.set(null);
    this.localStorageService.removeItem(LOCAL_STORAGE_KEY_USER_SESSION, true);
    this.localStorageService.removeItem(
      LOCAL_STORAGE_KEY_SELECTED_SESSION_ID,
      true,
    );
  }
}
